```class Solution {
public:
    string answerString(string word, int numFriends) {
        string res = "";
        for (int i = 0; i < word.length(); i++) {
            res += word[i];
            if (res.length() >= numFriends) {
                string temp = res;
                for (int j = 0; j < numFriends - 1; j++) {
                    temp += word[i + j + 1];
                }
                res = temp;
                i += numFriends - 1;
            }
        }
        return res;
    }
};```
